bool NePyStructPropSet_Math(const FStructProperty* InStructProp, FNePyStructBase* InSelf, void* InBuffer)
{
	if (FNePyStruct_Math* PyObj = NePyStructCheck_Math(InSelf))
	{
		InStructProp->Struct->CopyScriptStruct(InBuffer, PyObj->Value);
		return true;
	}
	return false;
}

FNePyStructBase* NePyStructPropGet_Math(const FStructProperty* InStructProp, const void* InBuffer)
{
	PyTypeObject* PyType = &FNePyStructType_Math;
	FNePyStruct_Math* PyObj = (FNePyStruct_Math*)PyType->tp_alloc(PyType, 0);
#if NEPY_ENABLE_STRUCT_DEEP_ACCESS
	PyObj->Value = (FMath*)InBuffer;
	PyObj->SelfCreatedValue = false;
#else
	PyObj->Value = (FMath*)FMemory::Malloc(sizeof(FMath), alignof(FMath));
	NePyBase::EnsureCopyToStructSafely<FMath>(InStructProp, PyObj->Value);
	InStructProp->Struct->CopyScriptStruct(PyObj->Value, InBuffer);
	PyObj->SelfCreatedValue = true;
#endif
	PyObj->PyOuter = nullptr;
	return PyObj;
}

PyTypeObject* NePyNePyWrappedStructInit_Math(const UScriptStruct* InScriptStruct, PyTypeObject* InPyBase)
{
	PyTypeObject* NePyStructType = &FNePyStructType_Math;
	TNePyStructBase<FMath>::InitTypeCommon(NePyStructType);
	NePyStructType->tp_methods = FNePyStructType_Math_methods;
	NePyStructType->tp_base = InPyBase;
	PyType_Ready(NePyStructType);

	if (InScriptStruct)
	{
		FNePyStructTypeInfo TypeInfo = {
			NePyStructType,
			ENePyTypeFlags::StaticPyType,
			(NePyStructPropSet)NePyStructPropSet_Math,
			(NePyStructPropGet)NePyStructPropGet_Math,
		};
		FNePyWrapperTypeRegistry::Get().RegisterWrappedStructType(InScriptStruct, TypeInfo);
	}

	return NePyStructType;
}

void NePyInitStruct_Math(PyObject* PyOuterModule)
{
	const UScriptStruct* ScriptStruct = FNePyStructBase::SearchScriptStruct(TEXT("/Script/CoreUObject"), TEXT("Math"));
	if (ScriptStruct)
	{
		FNePyWrapperInitializer::Get().RegisterWrappedStructInitFunc(
			ScriptStruct, NePyNePyWrappedStructInit_Math);
	}
	else
	{
		PyTypeObject* NePyStructType = NePyNePyWrappedStructInit_Math(nullptr, NePyStructBaseGetType());
		Py_INCREF(NePyStructType);
		PyModule_AddObject(PyOuterModule, "Math", (PyObject*)NePyStructType);
	}
}

FNePyStruct_Math* NePyStructNew_Math(const FMath& InValue)
{
	PyTypeObject* PyType = &FNePyStructType_Math;
	FNePyStruct_Math* RetValue = (FNePyStruct_Math*)PyType->tp_alloc(PyType, 0);
	if (FNePyStruct_Math::Init(RetValue, nullptr, nullptr) < 0)
	{
		Py_DECREF(RetValue);
		return nullptr;
	}
	new(RetValue->Value) FMath(InValue);
	return RetValue;
}

FNePyStruct_Math* NePyStructCheck_Math(PyObject* InPyObj)
{
	if (InPyObj && PyObject_TypeCheck(InPyObj, &FNePyStructType_Math))
	{
		return (FNePyStruct_Math*)InPyObj;
	}
	return nullptr;
}

PyTypeObject* NePyStructGetType_Math()
{
	return &FNePyStructType_Math;
}

namespace NePyBase
{
	bool ToCpp(PyObject* InPyObj, FMath& OutVal)
	{
		if (FNePyStruct_Math* PyObj = NePyStructCheck_Math(InPyObj))
		{
			OutVal = *(FMath*)PyObj->Value;
			return true;
		}
		return false;
	}

	bool ToPy(const FMath& InVal, PyObject*& OutPyObj)
	{
		OutPyObj = NePyStructNew_Math(InVal);
		return true;
	}
}
